 if($action==='category_add'){$name=trim($_POST['category_name']??'');if($name==='')$error='Kategori adı boş bırakılamaz.';else try{$order=(int)db()->query('SELECT COALESCE(MAX(sort_order),0)+1 FROM category_definitions')->fetchColumn();$s=db()->prepare('INSERT INTO category_definitions (name,sort_order) VALUES (?,?)');$s->execute([$name,$order]);$message='Kategori eklendi.';}catch(PDOException $e){$error='Bu kategori zaten tanımlı.';}}
 if($action==='category_delete'){$id=(int)($_POST['category_id']??0);$usage=db()->prepare('SELECT (SELECT COUNT(*) FROM items WHERE category_id=?) + (SELECT COUNT(*) FROM item_definitions WHERE category_id=?)');$usage->execute([$id,$id]);if((int)$usage->fetchColumn()>0)$error='Bu kategori eşya kayıtlarında kullanıldığı için silinemez.';else{$s=db()->prepare('DELETE FROM category_definitions WHERE id=?');$s->execute([$id]);$message='Kategori silindi.';}}
