 if($action==='item_definition_add'){$categoryId=(int)($_POST['item_category_id']??0);$name=trim($_POST['item_name']??'');$categoryStmt=db()->prepare('SELECT name FROM category_definitions WHERE id=? AND active=1');$categoryStmt->execute([$categoryId]);$category=$categoryStmt->fetchColumn();if(!$category||!$name)$error='Kategori ve eşya adı zorunludur.';else try{$order=(int)db()->query('SELECT COALESCE(MAX(sort_order),0)+1 FROM item_definitions')->fetchColumn();$s=db()->prepare('INSERT INTO item_definitions (category_id,category,name,sort_order) VALUES (?,?,?,?)');$s->execute([$categoryId,$category,$name,$order]);$message='Eşya tanımı eklendi.';}catch(PDOException $e){$error='Bu kategori altında aynı eşya zaten tanımlı.';}}
 if($action==='item_definition_delete'){$s=db()->prepare('DELETE FROM item_definitions WHERE id=?');$s->execute([(int)($_POST['item_definition_id']??0)]);$message='Eşya tanımı silindi.';}
 if($action==='item_definition_edit'){$id=(int)($_POST['item_definition_id']??0);$categoryId=(int)($_POST['item_category_id']??0);$name=trim($_POST['item_name']??'');$categoryStmt=db()->prepare('SELECT name FROM category_definitions WHERE id=? AND active=1');$categoryStmt->execute([$categoryId]);$category=$categoryStmt->fetchColumn();if(!$id||!$category||!$name)$error='Kategori ve eşya adı zorunludur.';else try{$s=db()->prepare('UPDATE item_definitions SET category_id=?,category=?,name=? WHERE id=?');$s->execute([$categoryId,$category,$name,$id]);$message='Eşya tanımı güncellendi.';}catch(PDOException $e){$error='Bu kategori altında aynı eşya zaten tanımlı.';}}
 if($action==='user'){$name=trim($_POST['name']??'');$email=trim(strtolower($_POST['email']??''));$password=$_POST['password']??'';$role=in_array($_POST['role']??'', ['Admin','User'],true)?$_POST['role']:'User';if(!$name||!filter_var($email,FILTER_VALIDATE_EMAIL)||strlen($password)<6)$error='Kullanıcı bilgilerini kontrol edin.';else{$check=db()->prepare('SELECT id FROM users WHERE LOWER(email)=LOWER(?) LIMIT 1');$check->execute([$email]);if($check->fetch())$error='Bu e-posta adresi zaten kullanılıyor. Aynı e-posta ile ikinci kullanıcı oluşturulamaz.';else try{$s=db()->prepare('INSERT INTO users (name,email,password_hash,role,active) VALUES (?,?,?,?,1)');$s->execute([$name,$email,password_hash($password,PASSWORD_DEFAULT),$role]);$message='Kullanıcı oluşturuldu.';}catch(PDOException $e){$error='Bu e-posta adresi zaten kullanılıyor. Aynı e-posta ile ikinci kullanıcı oluşturulamaz.';}}}
