</main><script>function editDefinition(form,current){const value=prompt('Yeni adı girin:',current);if(value===null||!value.trim())return false;form.querySelector('input[name$="_name"]').value=value.trim();return true}function editItem(form,category,name){const newCategory=prompt('Kategori:',category);if(newCategory===null)return false;const newName=prompt('Eşya adı:',name);if(newName===null||!newCategory.trim()||!newName.trim())return false;form.item_category.value=newCategory.trim();form.item_name.value=newName.trim();return true}const root=document.documentElement,themeButton=document.getElementById('theme-toggle'),themeIcon=themeButton.querySelector('.theme-icon');function setTheme(theme){root.dataset.theme=theme;localStorage.setItem('lf-theme',theme);const dark=theme==='dark';themeIcon.textContent=dark?'☾':'☼';themeButton.title=dark?'Gündüz görünümüne geç':'Gece görünümüne geç'}setTheme(localStorage.getItem('lf-theme')||'light');themeButton.addEventListener('click',()=>setTheme(root.dataset.theme==='dark'?'light':'dark'));const accountButton=document.getElementById('account-toggle'),dropdown=document.getElementById('account-dropdown');accountButton.addEventListener('click',event=>{event.stopPropagation();const open=dropdown.classList.toggle('open');accountButton.setAttribute('aria-expanded',open)});document.addEventListener('click',event=>{if(!dropdown.contains(event.target)){dropdown.classList.remove('open');accountButton.setAttribute('aria-expanded','false')}});</script><script src="<?=url('assets/required.js')?>"></script></body></html>
